// Kingdom Design Profile (MBTI) content: 16 type profiles, 4 temperaments,
// 4 preference pairs, clarity bands. Auto-generated from the source document
// by kingdom_build.py + gen_kingdom_js.py. Edit the source, not this file.

export const KDP_ORDER = ["ISTJ", "ISFJ", "ESTJ", "ESFJ", "ISTP", "ISFP", "ESTP", "ESFP", "INFJ", "INFP", "ENFJ", "ENFP", "INTJ", "INTP", "ENTJ", "ENTP"];
export const KDP_NAMES = {"ISTJ": "The Faithful Steward", "ISFJ": "The Quiet Defender", "ESTJ": "The Kingdom Administrator", "ESFJ": "The Shepherd Of The Flock", "ISTP": "The Practical Problem-Solver", "ISFP": "The Gentle Worshiper", "ESTP": "The Bold Responder", "ESFP": "The Joyful Encourager", "INFJ": "The Counselor", "INFP": "The Heart Of Compassion", "ENFJ": "The Mentor Of Hearts", "ENFP": "The Fire Starter", "INTJ": "The Master Planner", "INTP": "The Truth Seeker", "ENTJ": "The Kingdom Builder", "ENTP": "The Kingdom Innovator"};
export const KDP_TYPES = { "ISTJ": { "code": "ISTJ", "name": "The Faithful Steward", "mirror": "Nehemiah", "also": "Ezra; the faithful servant of Matthew 25:21", "snapshot": "You are dependable to the bone. You take commitments seriously, honor your word, remember what others forget, and quietly carry more responsibility than anyone realizes. You value order, accuracy, and proven methods. People may not always notice your work, but they always notice when someone like you is missing.", "wired": [ "Thorough, careful, and precise; you check the details others skip", "Loyal for the long haul, to people, churches, and institutions", "A memory for facts, dates, procedures, and past lessons", "Calm and duty-driven under pressure", "Honest and consistent; your walk matches your talk", "Frugal and wise with resources, yours and the church's" ], "mirror_story": "Before Nehemiah said one public word about rebuilding Jerusalem, he spent three days quietly inspecting the walls at night, gate by gate, counting the damage for himself (Nehemiah 2:11-16). Then he organized the entire city into work crews, family by family, section by section (Nehemiah 3). When enemies mocked and threatened, he posted guards, kept the workers armed, and refused to come down from the wall to be distracted: \"I am carrying on a great project and cannot go down\" (Nehemiah 6:3). Inspection first, organization second, faithfulness throughout. That is the ISTJ pattern sanctified for the Kingdom.", "kingdom": "The Kingdom advances on promises kept. God calls Himself faithful (Lamentations 3:22-23), and your steadiness is a living picture of His reliability to a generation that has been let down by nearly everyone. Your calling is to be the one who can be counted on, and to build ministries that outlast personalities because they rest on faithful systems and faithful people.", "church": { "roles": "treasurer or finance team, trustee, facilities and safety, records and membership, ushering and logistics, Sunday school administration, policy and bylaws work, long-term prayer commitments.", "lead": "By example and by system. You set the standard, document the process, and expect people to do what they said they would do.", "team_needs": "Your follow-through and your institutional memory. Also your honest warnings; you usually see the practical problem before anyone else does.", "you_need": "Clear expectations, respect for procedure, and appreciation expressed concretely rather than in vague praise." }, "family": [ "As a spouse, you show love through acts of service and provision more than through words. Say the words anyway; your family needs to hear them.", "You create security. Bills paid, cars maintained, promises kept. That security is a genuine ministry to your home.", "As a parent, you excel at consistency, routine, and teaching responsibility. Guard against letting rules crowd out relationship (Ephesians 6:4).", "Schedule fun on purpose. It will not happen by accident in your house, so put it on the calendar and protect it like an appointment." ], "relationships": [ "You have a few deep loyalties rather than many acquaintances, and you keep them for decades.", "You show care by showing up, on time, with what you promised.", "In conflict, you argue from facts and precedent. Remember that the other person's feelings are also facts you must weigh.", "You are slow to open up. Let trusted people see your inner life; hiddenness is not the same as holiness." ], "watchouts": [ "Rigidity: resisting change even when God is clearly in the change (Acts 10 was hard for people like you, and Peter needed the vision three times)", "Judging free-spirited people as irresponsible rather than differently designed", "Working past exhaustion out of duty, then growing resentful that no one helped", "Withholding affection and encouragement because \"they know how I feel\"", "Trusting your routine and diligence more than you trust God" ], "sanctification": "Grace. You naturally live by works and standards, which makes you a rock, but the gospel is not a checklist. Rest in what Christ finished (Ephesians 2:8-9), and extend to others the patience God extends to you.", "stress": "You go quiet, work harder, and become critical of everyone who is not working as hard. In deep stress you can spiral into worst-case \"what if\" thinking that is unlike your normal steady self. The remedy is rest, honest talk with a trusted friend, and Sabbath, which is a command and not a suggestion (Exodus 20:8-10).", "disc_natural": "Daily reading plans, Scripture memory, tithing, fasting on schedule, faithful intercession lists.", "disc_stretch": "Spontaneous worship, sharing your testimony aloud, praying freely in a group, celebration as a discipline.", "verses": [ "\"His master replied, 'Well done, good and faithful servant!'\" (Matthew 25:21)", "\"Let us not become weary in doing good, for at the proper time we will reap a harvest if we do not give up.\" (Galatians 6:9)", "\"Whatever you do, work at it with all your heart, as working for the Lord.\" (Colossians 3:23)" ], "prayer": "Father, thank You for making me steady in a shaking world. Keep my faithfulness fresh, so duty never hardens into drudgery or pride. Teach me to rest in Your finished work, to bend when You are doing a new thing, and to say the loving words my family needs to hear. Let me hear \"well done\" from You above all. In Jesus' name, amen.", "next30": [ "Tell one family member, out loud, something you appreciate about them every day this week.", "Identify one change at church you have been resisting. Pray honestly about whether the resistance is conviction or just comfort.", "Take one full Sabbath day with no productive work, and note what it stirs up in you." ], "temperament": "SJ" }, "ISFJ": { "code": "ISFJ", "name": "The Quiet Defender", "mirror": "Ruth", "also": "Dorcas (Acts 9:36-42); Timothy", "snapshot": "You are warmth wrapped in reliability. You notice what people need before they ask, remember the details that matter to them, and serve steadily without seeking the spotlight. You carry the practical love of Christ into kitchens, hospital rooms, nurseries, and quiet corners where the cameras never go.", "wired": [ "Deeply considerate; you remember birthdays, losses, and favorite meals", "Patient, gentle, and steady with people others find difficult", "Conscientious and thorough in everything you take on", "Protective of the vulnerable: children, the elderly, the overlooked", "Humble; you genuinely prefer serving to being seen", "Loyal through hardship, not just in sunshine" ], "mirror_story": "Ruth's greatness was quiet, practical, and relentless. She bound herself to a bitter, grieving mother-in-law when there was nothing to gain: \"Where you go I will go... your people will be my people and your God my God\" (Ruth 1:16). Then she lived that vow in ordinary work, gleaning grain from sunrise onward, day after day, until the whole town knew her character: \"All the people of my town know that you are a woman of noble character\" (Ruth 3:11). God wove her faithfulness into the family line of David and of Jesus Himself (Matthew 1:5). Quiet loyalty carries generational consequences.", "kingdom": "Jesus said the greatest in the Kingdom is the servant of all (Matthew 23:11), which means heaven ranks people almost exactly opposite to the way platforms do. Your calling is to embody the practical mercy of God, to guard the forgotten, and to prove by your steadiness that love is not a feeling but a long obedience.", "church": { "roles": "hospitality and meals ministry, nursery and children's ministry, care visitation, benevolence, prayer ministry, greeting, funeral dinners, behind-the-scenes event support, one-on-one discipleship.", "lead": "Quietly and by care. People follow you because they know you genuinely love them.", "team_needs": "Your eyes. You see the person everyone else missed and the practical detail everyone else forgot.", "you_need": "Specific appreciation, protection from being taken for granted, and permission to say no." }, "family": [ "You are the keeper of the home's warmth: traditions, comfort, remembered preferences, soft landings after hard days.", "As a spouse, you serve constantly and silently. Tell your spouse what you need; they are not able to read your mind, and silence breeds quiet resentment.", "As a parent, you are nurturing and devoted. Be careful not to do for your children what they should learn to do themselves.", "Your home is a ministry base. Hospitality is a spiritual gift in you (1 Peter 4:9), even if it is a simple table." ], "relationships": [ "You are slow to trust but bottomless once you do.", "You avoid conflict to keep the peace, but buried hurt does not decompose; it ferments. Learn to speak honestly and early (Matthew 18:15).", "You give far more than you ask. Let others serve you sometimes; receiving is also fellowship (John 13:8).", "Guard against friendships where you are only the giver." ], "watchouts": [ "Being overlooked and quietly hurt rather than speaking up", "Serving to the point of exhaustion, then feeling invisible", "Absorbing criticism deeply and replaying it for weeks", "Enabling irresponsible people because saying no feels unloving", "Resisting change because the familiar feels safe" ], "sanctification": "Identity. Your worth is not your usefulness. You are a child before you are a servant (Galatians 4:7). When you serve from acceptance instead of for acceptance, the same work becomes worship instead of weight.", "stress": "You keep smiling and serving while the tank runs dry, then hit a wall of discouragement, or erupt in a way that shocks everyone including you. In deep stress you can become uncharacteristically harsh and pessimistic. The remedy is rest, honest words to a safe person, and letting someone minister to you for a change.", "disc_natural": "Intercession for people by name, acts of mercy, hospitality, faithful attendance, journaling gratitude.", "disc_stretch": "Saying no as a spiritual act, public testimony, asking for help, bold prayers for yourself.", "verses": [ "\"God is not unjust; he will not forget your work and the love you have shown him as you have helped his people.\" (Hebrews 6:10)", "\"Serve wholeheartedly, as if you were serving the Lord, not people.\" (Ephesians 6:7)", "\"And whoever gives one of these little ones even a cup of cold water... he shall by no means lose his reward.\" (Matthew 10:42)" ], "prayer": "Lord Jesus, You washed feet, and You made me someone who understands why. Keep my serving joyful and my heart honest. Give me courage to speak when I am hurting, wisdom to rest before I am empty, and faith to believe that You see every hidden thing I do. Let me serve from Your love, not for it. Amen.", "next30": [ "Ask one trusted person for help with something this week, and let them actually do it.", "Speak up once, kindly and directly, about something you would normally swallow.", "Write down every act of service you do for one week. Then read Hebrews 6:10 over the list and thank God that He saw all of it." ], "temperament": "SJ" }, "ESTJ": { "code": "ESTJ", "name": "The Kingdom Administrator", "mirror": "Joshua", "also": "Lydia (Acts 16); James, the practical pastor of Jerusalem", "snapshot": "You get things done and you bring everyone else along. You are decisive, organized, direct, and responsible, the person people instinctively look to when something must actually happen. You believe in standards, accountability, and hard work, and you have little patience for excuses, including your own.", "wired": [ "A natural organizer of people, projects, and resources", "Decisive; you would rather make a good decision now than a perfect one never", "Direct and honest; people always know where they stand with you", "Strong work ethic and personal responsibility", "Guardian of standards, order, and fairness", "Practical realist; you deal in what actually works" ], "mirror_story": "Joshua spent forty years as Moses' aide-de-camp, learning the operation from the inside, and then took command of the most complex logistics project in the Old Testament: moving a nation across a river and through a conquest, tribe by tribe, city by city, in ordered ranks (Joshua 1-6). His leadership voice was clear and decisive: \"Choose for yourselves this day whom you will serve... But as for me and my household, we will serve the LORD\" (Joshua 24:15). Notice also what God had to say to this strong executive before the campaign began: \"Be strong and courageous. Do not be afraid... for the LORD your God will be with you wherever you go\" (Joshua 1:9). Even commanders need commanding.", "kingdom": "Vision without administration dies in committee. God gave the church administrators on purpose (1 Corinthians 12:28), and your calling is to turn God-given vision into schedules, budgets, teams, and completed work. You build the scaffolding that lets everyone else build.", "church": { "roles": "board or deacon leadership, ministry directing, event and conference management, building programs, finance oversight, men's or women's ministry leadership, missions logistics, anything with a deadline and a budget.", "lead": "Out front, with clear plans and clear expectations. You delegate well and inspect what you expect.", "team_needs": "Decisiveness, structure, and your remarkable ability to finish what the church starts.", "you_need": "Competence, honesty, and follow-through. Also patience when they process slower than you decide." }, "family": [ "You provide leadership, security, and order at home, and your family knows they can depend on you completely.", "Efficiency is your language; affection is theirs. A household is not a project team, and your spouse and children need warmth more than they need optimization.", "As a parent, you teach responsibility superbly. Make sure your children experience your delight, not only your standards (Colossians 3:21).", "Ask questions at the dinner table and listen without fixing. This will be hard. Do it anyway." ], "relationships": [ "You are loyal, dependable, and generous in practical ways.", "Your directness can land as harshness on gentler types. Truth is your gift; add tenderness and it becomes gold (Proverbs 16:24).", "In conflict you push to settle the issue now. Some people need an hour, or a day, to know what they feel. Give it to them.", "Respect is your currency. Remember that others trade in appreciation, encouragement, and presence." ], "watchouts": [ "Steamrolling quieter voices in meetings and at home", "Valuing the program over the people it was built for", "Impatience with weakness, grief, and slow healing, in others and in yourself", "Control: doing God's work in your own strength and calling it diligence", "Dismissing new ideas because the current system is yours" ], "sanctification": "Gentleness. Your strength is real, and God wants it clothed. \"Let your gentleness be evident to all. The Lord is near\" (Philippians 4:5). Jesus was meek, which is not weakness but strength under God's rein, and He got everything done.", "stress": "You take charge harder, talk louder, and work longer. In deep stress you can feel isolated and unappreciated, and uncharacteristic waves of emotion may surprise you. The remedy is honest fellowship with peers who can push back, genuine delegation, and remembering the battle belongs to the Lord (2 Chronicles 20:15).", "disc_natural": "Scheduled devotions, fasting with a purpose, serving through leadership, generous systematic giving.", "disc_stretch": "Silence and stillness (Psalm 46:10), listening prayer, confessing weakness to a brother or sister, letting someone else lead.", "verses": [ "\"But as for me and my household, we will serve the LORD.\" (Joshua 24:15)", "\"Whoever wants to become great among you must be your servant.\" (Mark 10:43)", "\"Unless the LORD builds the house, the builders labor in vain.\" (Psalm 127:1)" ], "prayer": "Lord of hosts, thank You for making me strong and decisive. Keep my strength surrendered. Guard me from building without You, from loving the mission more than the people, and from a home that gets my leftovers. Make me gentle without making me passive, and let everything I organize be scaffolding for Your glory, not mine. Amen.", "next30": [ "In your next three meetings, ask the quietest person in the room what they think, and count to ten before responding.", "Plan a family evening with no agenda except enjoying your people.", "Hand one significant responsibility fully to someone else, and do not take it back when they do it differently than you would." ], "temperament": "SJ" }, "ESFJ": { "code": "ESFJ", "name": "The Shepherd Of The Flock", "mirror": "Martha of Bethany", "also": "Aquila and Priscilla's open home (Romans 16:3-5)", "snapshot": "You are the relational glue of every group you join. Warm, organized, loyal, and tireless, you host, feed, remember, connect, include, and care. You know everyone's name and everyone's story, and your deepest joy is a room full of people who feel loved and looked after.", "wired": [ "Warm-hearted and genuinely people-first", "Organized and practical; your care shows up as real help, on time", "A gift for hospitality that makes strangers feel like family", "Harmony-seeking; you sense tension instantly and move to heal it", "Faithful in attendance, service, and tradition", "Generous with time, food, effort, and encouragement" ], "mirror_story": "Martha gets remembered for one rebuke, which is unfair, because Scripture also gives her one of the greatest confessions of faith in the Gospels. It was Martha who opened her home to Jesus in the first place (Luke 10:38), Martha who ran out to meet Him on the road while Mary sat in the house (John 11:20), and Martha who declared, \"I believe that you are the Messiah, the Son of God\" (John 11:27), before Lazarus walked out of the tomb. Jesus' gentle word to her was not \"stop serving.\" It was \"you are worried and upset about many things\" (Luke 10:41). The serving was her gift. The anxiety was her burden. He wants to keep the first and carry the second.", "kingdom": "The early church was built in homes like yours (Acts 2:46; Romans 16:5). Your calling is to make the love of God tangible: a set table, a remembered name, a visit at the right moment. You turn a congregation into a family, and families are what the Kingdom is made of.", "church": { "roles": "hospitality director, small group hosting, greeting and assimilation, women's or men's fellowship leadership, meal trains and benevolence, children's ministry, event hosting, membership care, welcome team.", "lead": "Personally. You lead by relationship, remembering everyone, and making sure every person is seen, fed, and included.", "team_needs": "Your radar for people who are drifting, hurting, or new, and your ability to mobilize practical care fast.", "you_need": "Verbal appreciation, harmony, and teammates who notice when you are the one who needs care." }, "family": [ "Your home is your masterpiece. Holidays, traditions, and gathered tables are your love made visible.", "As a spouse, you give constant practical devotion, and you need words of affirmation in return. Ask for them plainly instead of hoping.", "As a parent, you are attentive and involved. Beware of over-functioning: children need to struggle a little to grow strong.", "Do not measure your family's love by their participation in your plans. Sometimes they will want quiet, and it is not rejection." ], "relationships": [ "You are the one who keeps the group together: you call, you check in, you organize the reunion.", "You feel criticism and conflict deeply, and you can take sides quickly to defend people you love. Get both stories first (Proverbs 18:17).", "You need to be needed. Watch that helpfulness never becomes control wearing an apron.", "Being disliked, even by unreasonable people, wounds you. Live for the audience of One (Galatians 1:10)." ], "watchouts": [ "Worry and fretfulness about people and details (Martha's \"many things\")", "Overcommitting, then serving with a sigh instead of joy (2 Corinthians 9:7)", "Sweeping real problems under the rug to preserve surface peace", "Taking others' choices personally", "Gossip dressed up as \"sharing concerns\"; your relational network can heal or hurt" ], "sanctification": "Sitting down. Mary's portion is offered to you too. Service that never sits at Jesus' feet becomes anxious, resentful, and thin. The one thing needed is Him, and He will not take your gift of serving away; He will feed it (Luke 10:42).", "stress": "You over-function, over-talk, and over-worry, and you may become sharp with the very people you are serving. In deep stress you can spiral into criticism and doomsaying that feels alien to your warm nature. The remedy is to sit down, be fed, and let the to-do list wait while your soul catches up.", "disc_natural": "Hospitality as worship, corporate worship and fellowship, serving teams, praying aloud for others.", "disc_stretch": "Solitude, unhurried devotional time with no task attached, receiving ministry, keeping a confidence in prayer alone.", "verses": [ "\"Offer hospitality to one another without grumbling.\" (1 Peter 4:9)", "\"Martha, Martha... few things are needed, or indeed only one.\" (Luke 10:41-42)", "\"Cast all your anxiety on him because he cares for you.\" (1 Peter 5:7)" ], "prayer": "Jesus, thank You for a heart that loves to gather and feed Your people. You said You would build Your church, so let me set tables without carrying weights You never gave me. Teach me Mary's stillness without losing Martha's hands. Guard my tongue, quiet my worry, and let everyone who enters my home meet You there. Amen.", "next30": [ "Take fifteen minutes at Jesus' feet each morning before touching a single task.", "Say no to one good opportunity to protect your joy in the rest.", "When worry starts this week, pray 1 Peter 5:7 out loud and hand the person or problem to God by name." ], "temperament": "SJ" }, "ISTP": { "code": "ISTP", "name": "The Practical Problem-Solver", "mirror": "Thomas", "also": "Bezalel, the Spirit-filled craftsman (Exodus 31:1-5)", "snapshot": "You are calm, capable, and hands-on. You understand how things work, whether machines, systems, or situations, and you can fix most of them. You say little, watch everything, and act decisively when action is actually needed. You trust what you can test, and you have no use for hype.", "wired": [ "Mechanically and practically gifted; your hands are tools of ministry", "Cool head in a crisis; panic is not in your vocabulary", "Independent and self-reliant", "Efficient; you find the shortest real path to a working solution", "Observant; you notice how things actually function, not how they are supposed to", "Honest and unpretentious; you have no interest in image" ], "mirror_story": "Thomas gets a hard time for doubting, but look closer at his design. When Jesus turned toward Bethany and danger, it was Thomas who said flatly, \"Let us also go, that we may die with him\" (John 11:16). Realistic courage, no drama. And when the others reported a resurrection, Thomas asked for what any honest craftsman asks for: physical evidence he could touch (John 20:25). Here is the glory of the story: Jesus came back specifically for him and offered His hands and side without shaming him. Verified truth turned the pragmatist into a worshiper with the most direct confession in the Gospels: \"My Lord and my God!\" (John 20:28). God is not threatened by your need to test things. Test Him and see (Malachi 3:10; 1 Thessalonians 5:21).", "kingdom": "Bezalel was the first person Scripture describes as \"filled with the Spirit of God,\" and it was for craftsmanship (Exodus 31:3). The Kingdom needs people whose worship flows through competent hands. Your calling is to keep the mission actually running, and to model a faith that is tested, solid, and free of pretense, which is exactly the faith skeptics can respect.", "church": { "roles": "sound, video, and livestream tech, building maintenance, vehicle and equipment care, security and safety team, mission trip construction, disaster response, setup and teardown, IT.", "lead": "By competence. You will not seek the platform, but in a crisis everyone follows you because you visibly know what you are doing.", "team_needs": "Your troubleshooting under pressure and your honest, hype-free assessment of what will and will not work.", "you_need": "Freedom to work without micromanagement, clear objectives, and meetings that end." }, "family": [ "You show love through action: fixing, building, providing, teaching skills. Real, but not always legible. Add words and touch so the message arrives.", "You need solitude and hands-on hobbies to recharge; help your family see this as maintenance, not rejection.", "As a parent, you are fun, calm, and practical, and you teach by doing. Your kids will remember what you built together.", "Your spouse may experience your independence as distance. Invite them into your world; show them what you are working on." ], "relationships": [ "You are loyal in deed and sparse in word. The people who know you well trust you completely.", "In conflict you go quiet and factual, or just leave the room. Withdrawal feels like peace to you and abandonment to them; stay five more minutes.", "You dislike emotional pressure and drama. Be patient: for many people, emotion is information, not manipulation.", "Small talk drains you. Aim for shared activity; you connect best shoulder to shoulder rather than face to face." ], "watchouts": [ "Detachment: watching life, and church, from the back row as a spectator", "Avoiding commitment because it limits your freedom", "Cynicism toward emotional expression and expressive worship", "Escaping into projects, screens, or adrenaline when relationships get hard", "Private faith that never risks anything relational" ], "sanctification": "Engagement. Faith that only observes is the faith James warns about (James 2:17). Jesus touched lepers, wept openly, and stayed in hard conversations. Let God take your competent hands and attach a fully present heart to them.", "stress": "You withdraw further and go silent, or make a sudden impulsive move just to feel free. In deep stress you may uncharacteristically explode with emotion you have long stored. The remedy is physical work or exercise, then one honest conversation with one trusted person, before the pressure picks its own exit.", "disc_natural": "Serving with your hands, practical generosity, study of how things (and texts) actually work, prayer while working or driving.", "disc_stretch": "Corporate worship engagement, praying aloud, sharing your inner life, staying in fellowship when it gets emotional.", "verses": [ "\"Then he said to Thomas, 'Put your finger here; see my hands.'\" (John 20:27)", "\"Whatever your hand finds to do, do it with all your might.\" (Ecclesiastes 9:10)", "\"Test everything; hold fast what is good.\" (1 Thessalonians 5:21)" ], "prayer": "Lord, You made my hands skilled and my head clear, and You are not afraid of my questions. Thank You for showing Thomas Your scars. Show me too, and make my tested faith unshakable. Keep me from watching from a distance. Put my hands to Kingdom work and teach my quiet heart to stay in the room. My Lord and my God. Amen.", "next30": [ "Volunteer your specific skill for one need at church, and do the job start to finish.", "In your next disagreement, stay present and speak one sentence about what you feel, not just what you think.", "Take one honest question you have about God to Scripture and a mature believer instead of letting it idle." ], "temperament": "SP" }, "ISFP": { "code": "ISFP", "name": "The Gentle Worshiper", "mirror": "Mary of Bethany", "also": "David the young shepherd-psalmist (1 Samuel 16:11-23)", "snapshot": "You are quiet on the outside and deep on the inside. You experience God, beauty, and people intensely, and you express that depth through action, art, kindness, and presence more than through speeches. You are gentle, sensitive, fiercely loyal to your values, and far stronger than you appear.", "wired": [ "Deeply feeling; your inner life is rich, tender, and real", "Artistic and aesthetic; beauty moves you toward God", "Present-moment awareness; you truly see the person in front of you", "Kind to the hurting, the awkward, and the animal kingdom alike", "Humble and unassuming; you never perform your goodness", "Quietly courageous when a core value is on the line" ], "mirror_story": "Mary appears three times in the Gospels, and every time she is at the feet of Jesus: listening while dinner was cooking (Luke 10:39), grieving her brother (John 11:32), and finally breaking a jar of perfume worth a year's wages over Him while the room objected to the waste (John 12:3-5). She said almost nothing in any scene. Her love was expressed in presence, tears, and one extravagant act of beauty. The pragmatists called it waste. Jesus called it \"a beautiful thing,\" and promised it would be remembered wherever the gospel is preached (Mark 14:6-9). That is your design: worship that costs something, expressed without a microphone.", "kingdom": "The Kingdom needs people who bring beauty into worship and tenderness into care. Your calling is to love God extravagantly in your own voice, through music, art, craftsmanship, mercy, and quiet presence, and to remind a noisy church that God was in the gentle whisper (1 Kings 19:12).", "church": { "roles": "worship team and music, visual arts and decor, photography and media, children's and special-needs ministry, care for the elderly, prayer ministry, quiet acts of benevolence, comfort ministry to the grieving.", "lead": "By authenticity. You will rarely want the title, but your realness gives others permission to be real.", "team_needs": "Your sensitivity to people and to the Spirit's gentleness, and your eye for beauty that ministers without words.", "you_need": "Gentleness, sincere appreciation, no public spotlight without warning, and freedom from rigid micromanagement." }, "family": [ "You are the tender heart of your home, attuned to every mood under your roof.", "You avoid conflict, so hurts can go underground and quietly accumulate. Speak while wounds are small (Ephesians 4:26).", "As a parent, you are affectionate, playful, and accepting. Add structure; your children need rails as well as warmth.", "Make things with and for your family. Your love language often has sawdust, paint, music, or flour on it." ], "relationships": [ "You are a loyal, low-drama, deeply comforting friend.", "You share your inner world slowly. The people who earn it discover an ocean.", "Criticism lands on you like a wound, not a comment. Take hurts to God first, then to the person, instead of into hiding.", "Do not let more forceful personalities constantly override you. Meekness is strength under control, not the absence of a voice." ], "watchouts": [ "Passivity: letting life, and ministry decisions, just happen to you", "Escaping conflict rather than resolving it", "Self-criticism and quiet discouragement no one knows about", "Impulse decisions when feelings surge", "Hiding your gifts out of fear of the spotlight (Matthew 25:25 warns about buried talents)" ], "sanctification": "Courage. Your gentleness is a gift, and God wants to add boldness to it, the way David's harp and David's sling lived in the same hands. \"For the Spirit God gave us does not make us timid, but gives us power, love and self-discipline\" (2 Timothy 1:7).", "stress": "You withdraw, go quiet, and turn criticism inward. In deep stress you may become uncharacteristically harsh and critical of others and yourself. The remedy is time with God in beauty (outdoors helps you more than most), creative expression, and one safe person who can hear what you actually feel.", "disc_natural": "Worship through music and art, meditation on Scripture, solitude with God, quiet acts of mercy.", "disc_stretch": "Speaking truth in conflict, praying aloud in groups, sharing your testimony, planning and keeping long-term commitments.", "verses": [ "\"She has done a beautiful thing to me.\" (Mark 14:6)", "\"Worship the LORD in the splendor of holiness.\" (Psalm 96:9)", "\"For the Spirit God gave us does not make us timid, but gives us power, love and self-discipline.\" (2 Timothy 1:7)" ], "prayer": "Father, You see what I rarely say. Thank You for a heart that feels deeply and hands that make beauty. Receive everything I create as worship. Give me courage to speak, to stay in hard conversations, and to break my jar over Jesus without fearing the room's opinion. Be strength in my gentleness. Amen.", "next30": [ "Create something this month, a song, a meal, a photo, a garden bed, and offer it to God on purpose as worship.", "Have the one gentle, honest conversation you have been avoiding.", "Serve once in a way that stretches you toward visibility, even slightly, and note that you survived." ], "temperament": "SP" }, "ESTP": { "code": "ESTP", "name": "The Bold Responder", "mirror": "Peter", "also": "Joab the field commander; Samson redeemed (Hebrews 11:32)", "snapshot": "You are energy, nerve, and motion. You live fully in the present, read rooms and situations instantly, take risks others only discuss, and make things happen while committees are still scheduling their next meeting. People find you magnetic, funny, and impossible to ignore.", "wired": [ "Bold; you act while others hesitate", "Persuasive and quick on your feet", "Crisis-calm; emergencies focus you instead of freezing you", "Realistic and pragmatic; you deal in what works now", "Energetic and fun; you make work feel like adventure", "Alert to the moment; you notice everything happening around you" ], "mirror_story": "Peter is the only man in history besides Jesus to walk on water, and he got there the only way an ESTP would: \"Lord, if it's you, tell me to come,\" and then he was out of the boat (Matthew 14:28-29). He spoke first in nearly every scene, drew a sword against an arrest squad (John 18:10), sank when he looked at the wind, denied Christ under pressure, and wept bitterly. And then, restored by grace, that same out-of-the-boat boldness stood up at Pentecost and preached three thousand souls into the Kingdom in one morning (Acts 2:14, 41). God did not remove Peter's wiring. He redeemed it, filled it, and built the church's first great advances on it.", "kingdom": "The gospel advances on holy nerve. Your calling is to be the one who gets out of the boat: the first to speak, the first to go, the first to act in crisis. Sanctified boldness, aimed by the Spirit and anchored in discipline, moves the Kingdom into places careful people never reach.", "church": { "roles": "outreach and evangelism, youth ministry, security and emergency response, mission trips, sports and recreation ministry, new-venture launches, personal invitation (you can invite anyone to anything), fundraising challenges.", "lead": "From the front, in motion. You inspire by visible courage and contagious energy.", "team_needs": "Momentum, courage, and street-level realism about what will actually connect with real people.", "you_need": "Room to move, quick decisions, and follow-through partners who finish what you launch." }, "family": [ "You bring fun, adventure, and life to your home. Your kids' friends wish you were their parent.", "Consistency is your growth area: consistent presence, consistent discipline, consistent devotions. Boring faithfulness is the adventure you must choose daily (Luke 9:23).", "Your spouse needs depth as well as excitement. Sit still, ask questions, and listen past the two-minute mark.", "Watch impulse spending and impulse commitments; they tax the whole household." ], "relationships": [ "You are generous, spontaneous, and fiercely protective of your people.", "You use humor to dodge depth. Let trusted people past the entertainment layer.", "In conflict you confront fast and forget fast. Others bruise longer; circle back and repair (Matthew 5:23-24).", "Words fly out of you under pressure, like Peter. Slow the tongue (James 1:19); you cannot un-say things." ], "watchouts": [ "Impulsiveness: acting, speaking, spending, committing before praying", "Boredom with the ordinary seasons where most of discipleship happens", "Risk-taking that becomes recklessness with money, safety, or reputation", "Overconfidence: \"I will never fall away\" was Peter's line hours before the rooster (Matthew 26:33-34)", "Avoiding reflection, so mistakes repeat instead of teaching" ], "sanctification": "Self-control, the last-listed and, for you, hardest-won fruit of the Spirit (Galatians 5:23). Your throttle works; God is installing a steering wheel and brakes. Restored Peter learned to wait in an upper room for ten days before the biggest moment of his life. Waiting was the preparation for power.", "stress": "You act faster, joke harder, and take bigger risks, outrunning the feeling instead of facing it. In deep stress you may spin into uncharacteristic dark \"what does it all mean\" brooding. The remedy is stopping to face what you feel with God and one honest friend, physical exertion, and refusing major decisions in the heat of the moment.", "disc_natural": "Active service, evangelism, bold public prayer, generosity, fasting as a challenge.", "disc_stretch": "Stillness, meditation on Scripture, journaling, accountability that reviews decisions before you make them.", "verses": [ "\"Lord, if it's you, tell me to come to you on the water.\" (Matthew 14:28)", "\"Like a city whose walls are broken through is a person who lacks self-control.\" (Proverbs 25:28)", "\"But the fruit of the Spirit is... forbearance... gentleness and self-control.\" (Galatians 5:22-23)" ], "prayer": "Lord Jesus, thank You for nerve. You made me first out of the boat, and You know how often I sink. Do for me what You did for Peter: catch me, restore me, and aim me. Put Your brakes on my tongue and my impulses without ever quenching my fire. Make my boldness Yours, and spend it on souls. Amen.", "next30": [ "Institute a 24-hour prayer pause on every significant decision, purchase, and commitment this month.", "Sit in ten minutes of complete stillness with God, five days a week. No phone, no motion.", "Use your boldness on purpose: personally invite three people to church or share your story with them." ], "temperament": "SP" }, "ESFP": { "code": "ESFP", "name": "The Joyful Encourager", "mirror": "King David, the celebrant", "also": "the healed man leaping at the temple gate (Acts 3:8)", "snapshot": "You are sunshine with a schedule conflict. Warm, playful, generous, and fully alive in the present moment, you make people feel welcome, celebrated, and glad they came. Where you are, there is laughter, food, music, and somehow always room for one more.", "wired": [ "Radiant warmth; strangers feel like friends within minutes", "Natural celebration; you turn ordinary moments into occasions", "Generous and openhanded, sometimes past your budget", "Observant of people; you sense moods and needs in real time", "Flexible and fun-loving; interruptions are invitations to you", "Hands-on compassion; you show up in person, with something warm" ], "mirror_story": "David commanded armies and wrote laments, but his signature scene is pure ESFP: bringing the ark into Jerusalem \"dancing before the LORD with all his might,\" dressed down, dignity abandoned, distributing bread and cakes to the whole crowd (2 Samuel 6:14-19). When his wife Michal despised the display, his answer was the celebrant's creed: \"I will celebrate before the LORD... I will become even more undignified than this\" (2 Samuel 6:21-22). This is the man God called \"a man after my own heart\" (Acts 13:22), the man who appointed musicians and singers as a permanent fixture of worship (1 Chronicles 15:16). Joy before God is not shallow. It is warfare against despair.", "kingdom": "\"The joy of the LORD is your strength\" (Nehemiah 8:10). In a weary world, sanctified joy is evangelism. Your calling is to embody the welcome of God, to celebrate what heaven celebrates (Luke 15:7, 10), and to carry lightness into rooms heavy with grief, using presence, laughter, and practical warmth.", "church": { "roles": "greeting and first impressions, worship and music, children's and youth ministry, event and celebration planning, drama and creative arts, hospital and shut-in visitation (you brighten rooms), fellowship meals, camp ministry.", "lead": "By enthusiasm. People join things you are part of because you visibly love being there.", "team_needs": "Morale, welcome, and your instinct for making guests feel like family in ninety seconds.", "you_need": "Appreciation, fun woven into work, help with details and deadlines, and grace when you improvise." }, "family": [ "You are the fun, the spontaneity, and the soft lap of your home.", "Your children get your delight, which is a picture of the Father's delight (Zephaniah 3:17). Give them your consistency too: bedtimes, boundaries, and Bibles benefit from rhythm.", "Money leaks out of joyful hands. Build a simple budget with your spouse and treat it as freedom, not prison (Proverbs 21:20).", "In hard seasons, resist the urge to outrun sadness with activity. Your family needs you present in the valley, not just at the party." ], "relationships": [ "You collect friends effortlessly and keep the mood warm.", "Depth requires stillness, which costs you. Sit long enough for real conversations to surface.", "You avoid conflict and unpleasant subjects. Loving people sometimes means hard conversations (Proverbs 27:6).", "Your need to be liked can bend your convictions in the wrong room. Anchor your identity in God's approval (Galatians 1:10)." ], "watchouts": [ "Avoiding pain, boredom, and hard subjects with busyness and entertainment", "Impulsive spending and commitments", "Shallow roots: skimming devotionally while thriving socially (Matthew 13:5-6, 20-21)", "Sensitivity to criticism behind the sunny exterior", "Letting the crowd's opinion steer you" ], "sanctification": "Depth. Joy that lasts grows roots in secret. David danced in public because he worshiped in private for decades, in pastures and caves, writing psalms nobody heard but God. Build the hidden life (Psalm 1:2-3), and your joy will hold in winters.", "stress": "You get busier, louder, and more scattered, filling every silence. In deep stress you may crash into rare dark visions of worst cases and feel utterly alone in them. The remedy is slowing down with safe people, naming the real feeling out loud, and returning to simple rhythms of rest and Scripture.", "disc_natural": "Celebration, corporate worship, service, giving, fellowship, gratitude out loud.", "disc_stretch": "Solitude and silence, fasting (especially from entertainment), meditation, sitting with the grieving without fixing the mood.", "verses": [ "\"I will celebrate before the LORD.\" (2 Samuel 6:21)", "\"The joy of the LORD is your strength.\" (Nehemiah 8:10)", "\"Blessed is the one... whose delight is in the law of the LORD... like a tree planted by streams of water.\" (Psalm 1:1-3)" ], "prayer": "Father of lights, thank You for making me glad and making me welcoming. Keep my joy true, rooted deep in You and not in the room's applause. Teach me the discipline of stillness, the courage of hard conversations, and the faithfulness of hidden devotion, so the party I carry is Yours and it never runs dry. Amen.", "next30": [ "Spend fifteen quiet minutes with God each morning before checking your phone.", "Fast from entertainment one day each week and give the time to Scripture and prayer.", "Sit with one hurting person this month and just listen. Do not fix, entertain, or redirect. Presence only." ], "temperament": "SP" }, "INFJ": { "code": "INFJ", "name": "The Counselor", "mirror": "John the Beloved", "also": "Samuel, who heard the voice in the night (1 Samuel 3)", "snapshot": "You are the rarest type, and you have always known you were different. You read people at a depth that sometimes unsettles them, carry a lifelong sense of purpose, and burn quietly for a world set right. You are gentle in manner and immovable in conviction, a private person with a public burden.", "wired": [ "Deep insight into people; you perceive motives, wounds, and potential", "A strong inner sense of calling and destiny", "Compassion joined to conviction; tender heart, steel spine", "A love of depth: symbols, meaning, the unseen", "One-on-one ministry power; people tell you things they tell no one", "Long-range vision for what people and churches could become" ], "mirror_story": "John began as a \"son of thunder,\" ready to call fire down on a village (Luke 9:54), and grace refined that intensity into the deepest devotional writing in Scripture. He is the disciple found leaning on Jesus' chest (John 13:23), the one at the foot of the cross when the bold had fled (John 19:26-27), the first to believe at the empty tomb (John 20:8). His Gospel skips half the events the others record so it can tell you what they meant: light, bread, vine, shepherd, Word. In old age, exiled and alone on Patmos, he received the Revelation. The pattern is yours: intensity, intimacy, insight, and a message that outlives its messenger.", "kingdom": "The Kingdom needs people who see beneath the surface, of Scripture, of people, and of the times. Your calling is depth ministry: counseling, intercession, writing, mentoring, and vision. You are built to sit with one soul for two hours and to see ten years down the road, often in the same afternoon.", "church": { "roles": "counseling and pastoral care, one-on-one discipleship, intercessory prayer leadership, writing and teaching, altar ministry, vision and planning input, mentoring leaders, small groups built on honesty.", "lead": "From depth. You lead fewer people, further. Those you invest in are permanently marked.", "team_needs": "Your discernment. You sense what is really going on in people and meetings long before it surfaces.", "you_need": "Sincerity, advance notice, protection from constant crowds, and leaders who take your quiet warnings seriously." }, "family": [ "You crave deep connection with your spouse and can be disappointed by ordinary days. Release your loved ones from the impossible job of meeting soul-needs only God can meet (Psalm 62:5).", "You know your children's hearts uncannily well. Tell them what you see in them; your words of identity will shape their lives.", "You need solitude to remain kind. Build it into the family rhythm openly instead of stealing it guiltily.", "Share your inner world in installments. Your family cannot love what you never show them." ], "relationships": [ "You are the friend people call at 2 a.m., and the one who remembers the conversation from years ago.", "You give many people depth while few return it. Pursue the friendships that feed you too.", "When wounded or violated, you can close a door on someone suddenly and permanently. Practice Matthew 18:15 confrontation before the door swings shut.", "Not everyone can go as deep as you. Let surface-level people be dessert, not disappointment." ], "watchouts": [ "Perfectionism about yourself, your church, and your leaders", "Absorbing others' pain until it becomes your own crisis", "Privately harboring hurt while appearing gracious", "The sudden permanent door-slam on people who cross your convictions", "Believing your perceptions are always accurate; insight is a gift, not infallibility (1 Corinthians 13:9)" ], "sanctification": "Rest. You carry people, burdens, and the gap between what is and what should be. Jesus' invitation targets you by name: \"Come to me, all you who are weary and burdened, and I will give you rest\" (Matthew 11:28). The world's repair is His job. Your job is faithfulness in your assignment.", "stress": "You absorb and absorb, then abruptly shut down or withdraw entirely. In deep stress you may binge on uncharacteristic sensory escapes or snap at the people closest to you. The remedy is early solitude with God, saying no before overload, and one confidant who is allowed to carry you for a change.", "disc_natural": "Contemplative prayer, journaling, Scripture meditation, intercession, fasting.", "disc_stretch": "Celebration, resting without guilt, casual fellowship, voicing needs plainly, forgiving quickly and visibly.", "verses": [ "\"One of them, the disciple whom Jesus loved, was reclining next to him.\" (John 13:23)", "\"Come to me, all you who are weary and burdened, and I will give you rest.\" (Matthew 11:28)", "\"Dear friends, let us love one another, for love comes from God.\" (1 John 4:7)" ], "prayer": "Father, You made me to see deeply and to feel what others carry. Thank You for this strange and holy gift. Guard me from carrying what only Christ can carry, from perfectionism that poisons love, and from doors slammed in hurt. Let me lean on Jesus' chest like John, and from that place, love Your people long after my strength would have failed. Amen.", "next30": [ "Tell one safe person the burden you have been carrying alone.", "Reopen, prayerfully, one relationship you closed abruptly, if Scripture and wisdom permit.", "Take a half-day retreat with God: no tasks, no ministry prep, just Psalm 23 pace." ], "temperament": "NF" }, "INFP": { "code": "INFP", "name": "The Heart Of Compassion", "mirror": "Jeremiah", "also": "Hosea, whose marriage became the message; Mary's Magnificat pondering (Luke 1-2)", "snapshot": "You are an idealist with an artist's soul and a martyr's convictions. Outwardly easygoing, inwardly you burn with values you would die for. You feel everything: the beauty, the suffering, the gap between the world as it is and as God means it to be. You are gentle, creative, authentic to the core, and allergic to hypocrisy.", "wired": [ "A profound inner life of values, imagination, and faith", "Empathy that crosses every boundary; you feel with the outcast instantly", "Creative gifts: words, music, art, story", "Authenticity; you cannot pretend, and you spot pretense instantly", "Devotion; when you commit to a person or cause, it is total", "Mercy for the failing and the broken, because you know your own depths" ], "mirror_story": "Jeremiah protested his calling: \"I do not know how to speak; I am too young\" (Jeremiah 1:6). God answered that He had formed him and known him before the womb (Jeremiah 1:5), which is the deepest need of your type: identity before assignment. For forty years Jeremiah preached truth nobody wanted, wept over a city that mocked him (\"the weeping prophet,\" Jeremiah 9:1), tried once to quit, and could not, because \"his word is in my heart like a fire, a fire shut up in my bones\" (Jeremiah 20:9). And it was this bruised idealist who was given the tenderest promises in the prophets: a new covenant written on hearts (Jeremiah 31:31-33) and plans of hope and a future (Jeremiah 29:11). Deep feelers carry deep revelation.", "kingdom": "The Kingdom needs consciences and comforters, people who cannot look away from suffering and cannot make peace with hypocrisy. Your calling is to give the church its heart language: to write, sing, pray, and love in ways that make grace believable to the broken.", "church": { "roles": "writing and communications, worship songwriting and arts, mercy and compassion ministries, missions with the marginalized, prayer ministry, one-on-one care for the hurting, recovery ministry, advocacy for the overlooked.", "lead": "By moral vision and personal authenticity. You lead best from conviction, not from org charts.", "team_needs": "Your conscience and your compassion. You keep the ministry honest and humane.", "you_need": "Sincerity, value alignment, gentle handling of criticism, and structure support for details and deadlines." }, "family": [ "You love your people with an ideal, poetic love. Real families are gloriously unpoetic; love the actual, snoring, dish-leaving versions (1 John 3:18).", "Your children will remember that you truly listened and truly saw them.", "Practical structure (budgets, calendars, maintenance) is not your native land. Build simple systems or partner with your spouse's strengths.", "When hurt, you retreat into silence and imagination. Come back and speak; your family cannot repair what they cannot see." ], "relationships": [ "You are among the most accepting and loyal friends alive.", "You idealize people, then feel betrayed by their ordinary flaws. Move your ideals from people to God, who alone can hold them (Psalm 118:8).", "Conflict feels like violence to you, so you delay it, which compounds it. Gentle honesty early is mercy to everyone.", "You need one or two soul-level friendships more than you need a crowd. Invest accordingly." ], "watchouts": [ "Melancholy and rumination that spiral into hopelessness", "Withdrawing from a real church because it fails your ideal church", "Procrastination on practical matters until they become crises", "Taking every criticism as a verdict on your soul", "Serving causes at the expense of the people in your own house" ], "sanctification": "Hope with skin on it. Your inner fire is from God, but idealism must be crucified into hope, which loves imperfect things as they are being redeemed. \"We wait for the blessed hope\" (Titus 2:13). The church is a bride in mid-makeover; love her like Christ does (Ephesians 5:25-27).", "stress": "You retreat inward, replay wounds, and lose motivation for ordinary tasks. In deep stress you may turn sharply critical and cold, judging everyone by standards no one could meet. The remedy is expression (write it, sing it, pray it aloud), sunlight and movement, and a trusted voice who reminds you what is true when feelings lie.", "disc_natural": "Journaling prayer, meditation on Scripture, worship in solitude, creative devotion, compassion ministry.", "disc_stretch": "Routine and consistency, finishing projects, corporate commitment through disappointing seasons, receiving criticism without inner collapse.", "verses": [ "\"Before I formed you in the womb I knew you.\" (Jeremiah 1:5)", "\"He has sent me to bind up the brokenhearted.\" (Isaiah 61:1)", "\"Let us not love with words or speech but with actions and in truth.\" (1 John 3:18)" ], "prayer": "Lord, You knew me before You formed me, and You put this fire in my bones. Thank You for a heart that cannot stop feeling. Marry my ideals to Your patience. Teach me to love real people, real churches, and my real self in mid-redemption. And let everything I write, sing, and pray bind up someone broken. Amen.", "next30": [ "Finish one meaningful project you have left half-done, and dedicate it to God.", "Each time disappointment with a person or the church surfaces, pray one sentence of blessing over them on the spot.", "Put your compassion in your body: one concrete act of mercy each week, in person." ], "temperament": "NF" }, "ENFJ": { "code": "ENFJ", "name": "The Mentor Of Hearts", "mirror": "Barnabas", "also": "Priscilla, discipler of Apollos (Acts 18:26); Nehemiah's rallying speeches", "snapshot": "You were born to grow people. Warm, persuasive, organized, and relationally brilliant, you see the gold in people before they see it themselves, and you cannot rest until you have called it out. Rooms warm up when you enter. People leave conversations with you believing they can do more than they thought.", "wired": [ "A catalyst's gift: you develop people almost involuntarily", "Persuasive, articulate communication", "Empathy plus organization, a rare and powerful pairing", "Harmony-building; you unite factions and smooth conflicts", "Loyalty and encouragement in generous, constant supply", "Vision for people: you see who they could become in Christ" ], "mirror_story": "His name was Joseph, but the apostles renamed him \"Barnabas,\" Son of Encouragement, because encouragement was simply what he was (Acts 4:36). Track his fingerprints: he sold a field for the church's poor (Acts 4:37); he alone vouched for the converted Saul when everyone else was afraid of him (Acts 9:26-27); sent to inspect the suspect new church at Antioch, \"he saw what the grace of God had done\" and was glad (Acts 11:23); he went and fetched Saul to co-pastor there (Acts 11:25-26); and when Paul gave up on young John Mark, Barnabas took Mark and rebuilt him (Acts 15:37-39), which is why the church has the Gospel of Mark. Half the New Testament exists downstream of one encourager's belief in two ruined men. That is your job description.", "kingdom": "Ephesians 4:12 says leaders exist \"to equip his people for works of service.\" You are a walking Ephesians 4:12. Your calling is multiplication: finding the Sauls and Marks everyone else has written off or overlooked, and developing them until they outgrow you, which will be your joy, not your threat.", "church": { "roles": "discipleship and mentoring leadership, teaching and preaching, small group ministry director, leadership development, women's or men's ministry, worship leading, counseling, assimilation and connections, reconciliation work.", "lead": "Relationally and inspirationally. You lead people, not programs, and they follow because they know you believe in them.", "team_needs": "Your eye for potential, your morale-building, and your ability to say hard things so warmly they get received.", "you_need": "Appreciation expressed, authenticity, shared load, and honest peers who notice when your own tank is empty." }, "family": [ "You are your family's chief encourager and event planner, attuned to every member's growth.", "You can smother with helpfulness. Let your spouse and children struggle productively; rescue less, coach more.", "Your family gets your warmth; make sure they also get your honesty about your own needs and failures. Be a person at home, not a pastor.", "Guard the calendar. Your yes to everyone else is often a no to your own household (1 Timothy 3:4-5 puts the household first)." ], "relationships": [ "You maintain a huge relational network and remember everyone's story.", "You need affirmation more than you admit, and criticism cuts you deeply. Take it first to God, who defines you (Zephaniah 3:17).", "You avoid conflicts that might rupture harmony, and you can sweep your own hurts under communal rugs. Honesty is a form of love you owe your friends.", "Beware people-pleasing drift: adjusting convictions to keep the room warm (Proverbs 29:25)." ], "watchouts": [ "Overcommitment and burnout; every need looks like your assignment", "Measuring your worth by others' growth and approval", "Manipulating (even benevolently) because you know exactly what to say to move people", "Neglecting your own soul while feeding everyone else's", "Taking over-responsibility for outcomes only God controls (1 Corinthians 3:6-7)" ], "sanctification": "Sourcing. Encouragement flows out of you, but whose voice fills you? If it is the crowd's, you will ride their moods to burnout. Live from the Father's affirmation, as Jesus did before He had done any ministry at all: \"This is my Son, whom I love; with him I am well pleased\" (Matthew 3:17, spoken before a single miracle).", "stress": "You over-give, over-schedule, and keep smiling while depleting. In deep stress you may become uncharacteristically harsh, critical, and withdrawn, shocking those who know you. The remedy is retreat with God, honest confession of limits, and letting yourself be pastored.", "disc_natural": "Encouraging others with Scripture, corporate worship, mentoring, hospitality, intercession for people by name.", "disc_stretch": "Solitude, silence, receiving correction gladly, saying no, being ministered to without reciprocating.", "verses": [ "\"Joseph... whom the apostles called Barnabas (which means 'son of encouragement').\" (Acts 4:36)", "\"And let us consider how we may spur one another on toward love and good deeds.\" (Hebrews 10:24)", "\"I planted the seed, Apollos watered it, but God has been making it grow.\" (1 Corinthians 3:6)" ], "prayer": "Father, thank You for letting me see the gold You hide in people. Keep me generous like Barnabas, brave enough to vouch for the Sauls and patient enough to rebuild the Marks. Guard me from living on applause. Fill me first, so I pour from overflow and not from emptiness, and let everyone I develop love You more than they admire me. Amen.", "next30": [ "Choose your Mark: one overlooked or written-off person to intentionally encourage all month.", "Cancel or decline one commitment, and give that time to solitude with God.", "Ask one honest friend, \"Where do I perform instead of confess?\" and receive the answer without defending yourself." ], "temperament": "NF" }, "ENFP": { "code": "ENFP", "name": "The Fire Starter", "mirror": "Apollos", "also": "the woman at the well who evangelized her town (John 4:28-30, 39)", "snapshot": "You are contagious enthusiasm with a genuine heart. Ideas, people, and possibilities light you up, and you light up everyone around you. You see potential everywhere, start movements over coffee, make outsiders feel like insiders, and bring imagination to everything you touch. Routine is your kryptonite; vision is your oxygen.", "wired": [ "Infectious enthusiasm that mobilizes people", "Creativity; you generate ten ideas before breakfast", "Warmth that makes every kind of person feel valued", "Verbal gifting: story, humor, persuasion", "Fierce belief in people and possibilities", "Spiritual passion; when you are lit, everyone near you feels the heat" ], "mirror_story": "Apollos arrived in Ephesus as raw fire: \"a learned man, with a thorough knowledge of the Scriptures... he spoke with great fervor,\" yet his doctrine had gaps, knowing only the baptism of John (Acts 18:24-25). Here is the beautiful part: when Priscilla and Aquila took him aside and explained the way of God more adequately, he received it (Acts 18:26). Fervor plus teachability is unstoppable. The result: \"he vigorously refuted his Jewish opponents in public debate... he was a great help to those who by grace had believed\" (Acts 18:27-28), and his ministry grew so powerful that some in Corinth ranked him with Paul and Peter (1 Corinthians 1:12). Paul's verdict settles your value: \"I planted the seed, Apollos watered it\" (1 Corinthians 3:6). The Kingdom needs waterers who make truth exciting.", "kingdom": "Every move of God spreads on the enthusiasm of people like you. Your calling is ignition: evangelism, vision-casting, mobilizing volunteers, launching ministries, and making the ancient gospel sound like this morning's news, because to you it is.", "church": { "roles": "evangelism and outreach, youth and young adult ministry, creative arts and communications, vision teams, new ministry launches, camp and conference speaking, worship, welcoming and assimilation, short-term missions mobilization.", "lead": "By inspiration. You paint the picture, gather the people, and generate liftoff.", "team_needs": "Ignition, creativity, and your gift for making newcomers feel instantly wanted.", "you_need": "Freedom to innovate, finishing partners who carry details, encouragement, and honest structure that channels your fire without smothering it." }, "family": [ "Your home is full of spontaneity, affection, and big dreams out loud.", "Your follow-through gap lands hardest on the people who count on you. Let your yes be yes (Matthew 5:37); fewer promises, kept fully.", "Children adore you. Anchor their adoration with routines they can count on: prayers, bedtimes, traditions.", "In marriage, novelty fades and covenant remains. When the feelings dip, that is not the marriage failing; that is where covenant love begins its best work (Malachi 2:14-15)." ], "relationships": [ "You befriend everyone and genuinely mean it.", "Depth requires staying power. Resist trading aging friendships for shiny new ones.", "You overpromise from real enthusiasm, then wound people by under-delivering. Track commitments in writing.", "In conflict you feel attacked quickly and can catastrophize a relationship's future. Stay present; most conflicts are chapters, not endings." ], "watchouts": [ "Starting what you never finish, in projects and in disciplines", "Emotional and spiritual highs mistaken for depth; lows mistaken for abandonment", "Scattered focus: ten callings pursued at two percent each", "Craving affirmation and novelty more than obedience", "Teachability failure: fervor that stops receiving correction (Apollos' greatness hinged on Acts 18:26)" ], "sanctification": "Faithfulness in the small and the same. \"Whoever can be trusted with very little can also be trusted with much\" (Luke 16:10). God grows oaks slowly. Your fire is His gift; the altar that keeps it burning is daily, boring, glorious routine (Leviticus 6:12-13: the fire must be kept burning, every morning, by somebody faithful).", "stress": "You scatter further, overcommit worse, and swing emotionally. In deep stress you may fixate uncharacteristically on one gloomy detail or bodily worry and cannot release it. The remedy is radical simplification (fewer plates spinning), body care and sleep, and one steady friend who helps you sort real obligations from imagined ones.", "disc_natural": "Expressive worship, testimony, conversational prayer, fellowship, fasting begun enthusiastically.", "disc_stretch": "The same devotional time at the same hour daily, Scripture memory, finishing a whole book study, silence, staying planted in one church through a dull season.", "verses": [ "\"He spoke with great fervor and taught about Jesus accurately.\" (Acts 18:25)", "\"Never be lacking in zeal, but keep your spiritual fervor, serving the Lord.\" (Romans 12:11)", "\"Whoever can be trusted with very little can also be trusted with much.\" (Luke 16:10)" ], "prayer": "Lord, thank You for fire. You made me to ignite and to water, to make Your good news sound as good as it is. Keep me teachable like Apollos when the Priscillas pull me aside. Teach me the holiness of routine, the power of a kept promise, and the depth that only sameness can grow. Let me finish what You start in me. Amen.", "next30": [ "Pick ONE ministry idea and take it to completion before starting anything new.", "Keep the same fifteen-minute devotional appointment at the same time for thirty straight days.", "Review your outstanding promises, list them, and either fulfill or honestly release each one." ], "temperament": "NF" }, "INTJ": { "code": "INTJ", "name": "The Master Planner", "mirror": "Daniel", "also": "Joseph, administrator of Egypt (Genesis 41); Isaiah's long-range visions", "snapshot": "You are strategy in human form. You see systems, patterns, and ten-year horizons, hold yourself to punishing standards, and quietly assume there is a better way to do almost everything, because you have usually already designed it. You are independent, private, disciplined, and immune to peer pressure.", "wired": [ "Long-range vision; you live comfortably a decade ahead", "Systems thinking; you see how everything connects", "Independence of mind; crowds do not move you", "Relentless self-discipline and high standards", "Depth of focus that produces mastery", "Conviction; when you know something is right, pressure is irrelevant" ], "mirror_story": "Daniel was a teenager in a hostile empire when he \"resolved not to defile himself\" (Daniel 1:8), a private conviction made long before the test came, which is exactly how your type operates. He mastered the literature of Babylon, out-performed every advisor (Daniel 1:20), interpreted dreams that stumped the establishment, and served with such excellence across multiple hostile administrations that his enemies auditing him \"could find no corruption in him\" (Daniel 6:4). His secret was a system: windows open toward Jerusalem, three times a day, \"just as he had done before\" (Daniel 6:10). Strategic mind, incorruptible standards, unshakable routine, seventy years of influence at the highest levels of two empires. That is the sanctified INTJ.", "kingdom": "God places strategists in courts, boardrooms, and back offices to give His people wisdom beyond their numbers. Your calling is to think long, plan deep, and hold standards, to be the one who designs the ministry that outlives its founders and who cannot be bought, flattered, or rushed.", "church": { "roles": "strategic planning, doctrine and teaching, building and expansion projects, finance and investment oversight, curriculum design, policy development, apologetics, long-range missions strategy, technology architecture.", "lead": "By vision and competence. You lead from the drawing board and hold the line on quality and doctrine.", "team_needs": "The ten-year view, the honest analysis nobody else will voice, and plans that actually work.", "you_need": "Competence, logic, autonomy, and leaders who can hear critique without hearing rebellion." }, "family": [ "You show love by planning for your family's future: education, finances, security. Tell them the plan is love, and then also say the love out loud.", "Your standards can feel like a report card to your spouse and children. Grace at home first (Colossians 3:19, 21).", "Schedule presence, not just provision. Your child's recital deserves the same calendar authority as a board meeting.", "Let your family see you fail and laugh about it. Your humanity will bless them more than your excellence does." ], "relationships": [ "You have few friends and lifelong ones; entrance is slow, exit is rare.", "You process feeling privately, so people assume you have none. Give trusted people the summary, at least.", "In conflict you are calm, logical, and devastating. Win the person, not the argument (Proverbs 15:1).", "Suffer fools patiently. Christ suffers us all patiently, and \"knowledge puffs up while love builds up\" (1 Corinthians 8:1)." ], "watchouts": [ "Intellectual pride and quiet contempt for slower processors", "Trusting the plan more than the God the plan serves (Proverbs 19:21)", "Isolation; you can live a whole secret life of thought no one is allowed into", "Criticism as default output; encouragement withheld as unearned", "Skepticism toward emotional and expressive moves of the Spirit" ], "sanctification": "Dependence. Your competence is real, which makes self-sufficiency your most plausible idol. \"Trust in the LORD with all your heart and lean not on your own understanding\" (Proverbs 3:5). Daniel's power was not the strategy; it was the open window, three times a day, on his knees.", "stress": "You go colder, work longer, and withdraw into the fortress of your mind. In deep stress you may uncharacteristically overindulge the senses (food, drink, spending, screens) or obsess over minor physical details. The remedy is voiced honesty with God and one person, physical activity, and returning to worship that engages more than your intellect.", "disc_natural": "Systematic theology and deep study, disciplined prayer routine, fasting, long-term Scripture plans, stewardship.", "disc_stretch": "Corporate emotional worship, testimony, being led by others, spontaneous obedience, celebrating imperfect progress.", "verses": [ "\"But Daniel resolved not to defile himself.\" (Daniel 1:8)", "\"Trust in the LORD with all your heart and lean not on your own understanding.\" (Proverbs 3:5-6)", "\"Many are the plans in a person's heart, but it is the LORD's purpose that prevails.\" (Proverbs 19:21)" ], "prayer": "God of Daniel, thank You for a mind that sees far and stands firm. Take my plans; they were always Yours. Keep my window open toward You three times a day, so my strategy stays on its knees. Soften my standards into grace for the people I love, and let my competence make You look great, not me. Amen.", "next30": [ "Encourage specifically, out loud, one person per day, with zero critique attached.", "Submit one significant plan to your leaders or spouse for input, and genuinely incorporate what they say.", "Build your Daniel-window: three brief, fixed prayer stops in every workday." ], "temperament": "NT" }, "INTP": { "code": "INTP", "name": "The Truth Seeker", "mirror": "Luke the investigator", "also": "the Bereans, who examined everything (Acts 17:11); Ecclesiastes' searching Teacher", "snapshot": "You live to understand. You take ideas apart the way mechanics take apart engines, spot the flaw in any argument within minutes, and hold a private map of how everything works that you are perpetually revising. You are easygoing on the surface, rigorous underneath, and utterly independent in thought.", "wired": [ "Analytical precision; contradictions cannot hide from you", "Objectivity; you follow evidence even against your own preferences", "Deep curiosity across every field you touch", "Intellectual honesty; you say \"I don't know\" when you don't", "Innovative theory-building; you see explanations others miss", "Calm detachment that stays fair when everyone else is heated" ], "mirror_story": "Luke was a physician (Colossians 4:14), trained in observation, and the only Gentile author in your Bible. Listen to how he opens his Gospel: \"I myself have carefully investigated everything from the beginning... to write an orderly account... so that you may know the certainty of the things you have been taught\" (Luke 1:3-4). Interviews, eyewitnesses, documents, chronology: a researcher's method in service of faith. His two volumes, Luke and Acts, make up more of the New Testament by length than any other author's work. And note the Bereans, whom Scripture praises as \"of more noble character\" precisely because they \"examined the Scriptures every day to see if what Paul said was true\" (Acts 17:11). God is not offended by verification. He invites it.", "kingdom": "Every generation faces new questions, and the church needs minds that can meet them without flinching. Your calling is understanding in service of certainty for others: research, teaching, apologetics, and the patient untangling of hard questions so that seekers and doubters find the faith intellectually solid, because you checked.", "church": { "roles": "teaching and doctrine, apologetics and Q&A forums, curriculum research, Bible translation and original-language study, technology and systems, theology reading groups, mentoring analytical young believers who think they are the only ones with questions.", "lead": "By expertise. You lead ideas more naturally than departments, and that is a real form of leadership.", "team_needs": "Rigor. You catch the doctrinal drift, the flawed plan, and the unexamined assumption before they become expensive.", "you_need": "Intellectual respect, freedom to explore, tolerance for your bluntness, and grace for your absent-mindedness about practical details." }, "family": [ "You love by sharing your mind. Also share your time and your presence; your family cannot cite your affection from inference alone.", "Feelings are data you tend to file for later. Your spouse needs them processed out loud, at least sometimes (1 Peter 3:7 says live with understanding).", "As a parent you answer every \"why\" wonderfully. Also hug, attend, and celebrate; children spell love with attention, not accuracy.", "Household logistics bore you into negligence. Systematize the basics so love does not get undermined by unpaid bills." ], "relationships": [ "You are low-maintenance, fair, and never manipulative.", "You correct people reflexively. Ration it; most conversations are fellowship, not peer review (Romans 12:16).", "Emotional support does not come naturally, but presence counts. Show up; you do not have to fix or say much.", "You drift from people through sheer inattention. Calendar your friendships if you must; faithfulness can be engineered." ], "watchouts": [ "Analysis paralysis: eternally studying, rarely committing (2 Timothy 3:7 warns of \"always learning\" without arriving)", "Debating faith instead of living it", "Detachment that reads as coldness to the people who love you", "Procrastination on everything practical", "Pride in being the smartest person in the room, and arranging rooms accordingly" ], "sanctification": "Obedience ahead of full understanding. You want the complete map before you move; God gives lamplight for the next step (Psalm 119:105). \"Anyone who chooses to do the will of God will find out whether my teaching comes from God\" (John 7:17). In the Kingdom, doing is often how knowing arrives.", "stress": "You retreat into your head and your projects, going quiet for days. In deep stress you may erupt with surprising emotional intensity or become uncharacteristically needy about what others think of you. The remedy is talking before the pressure peaks, physical routine, and worship that bypasses analysis: singing, gratitude, kneeling.", "disc_natural": "Deep Bible study, theological reading, apologetics, meditation on hard texts, honest solitary prayer.", "disc_stretch": "Corporate worship participation, serving with your hands, fixed routines, praying aloud, acting on truth you cannot yet fully systematize.", "verses": [ "\"I myself have carefully investigated everything from the beginning... so that you may know the certainty.\" (Luke 1:3-4)", "\"They... examined the Scriptures every day to see if what Paul said was true.\" (Acts 17:11)", "\"Your word is a lamp for my feet, a light on my path.\" (Psalm 119:105)" ], "prayer": "God of all truth, thank You that You are not afraid of my questions and You do not ask me to unscrew my head to follow You. Make me like Luke: rigorous for the sake of others' certainty. Keep my analysis humble, my debates kind, and my obedience ahead of my understanding. Be not only the answer I seek but the God I love. Amen.", "next30": [ "Pick one truth you are fully convinced of and act on it concretely this week, before studying anything new.", "Serve once with your hands in a ministry that involves zero abstraction.", "Tell one person in your family something you feel, in feeling words, without an analytical frame around it." ], "temperament": "NT" }, "ENTJ": { "code": "ENTJ", "name": "The Kingdom Builder", "mirror": "The Apostle Paul", "also": "Deborah, who led a nation (Judges 4-5); Solomon the builder-king", "snapshot": "You are command presence with a blueprint. You see what should exist, mobilize people and resources to build it, and push through obstacles that stop everyone else. You think in strategies, speak in decisions, and measure life in results. Leadership is not something you seek; it is something that keeps happening to you.", "wired": [ "Natural command; rooms organize around you", "Strategic vision joined to executive drive", "Decisiveness under pressure", "Frankness; people never wonder what you think", "Tireless capacity for work and challenge", "Ability to turn vision into structures, teams, and results" ], "mirror_story": "Before Damascus, Saul was already an ENTJ: zealous, credentialed, mobilized, and ruthlessly effective, just aimed wrong (Philippians 3:4-6). Grace did not delete his drive; it redirected it. The same force that organized persecutions then planted churches across four Roman provinces, executed a multi-year, multi-nation relief fund (2 Corinthians 8-9), trained and deployed leaders like Timothy and Titus, argued before governors and kings, and wrote a third of the New Testament, much of it from prison, where he kept right on working (Philippians 1:12-13). His secret was a thorn: \"My grace is sufficient for you, for my power is made perfect in weakness\" (2 Corinthians 12:9). God loves to save drivers. Then He teaches them who is driving.", "kingdom": "Movements need generals. Your calling is to build what outlasts you: churches, institutions, campaigns, and leaders. When your force is surrendered, you accomplish in a decade what committees would not attempt in a century, and you raise up builders behind you.", "church": { "roles": "senior leadership, church planting, capital campaigns, organizational turnaround, denominational leadership, missions strategy, executive teams, leadership pipelines, anything stalled that needs force applied.", "lead": "From the front, at speed, with a plan. You cast vision, set structure, demand excellence, and develop strong leaders, because weak ones frustrate you.", "team_needs": "Direction, decisiveness, and protection. Teams under you know where they are going and that someone is in charge.", "you_need": "Competence, candor, and speed. Also, brave people who will tell you when you are wrong, so prize your truth-tellers; they are rarer than your admirers." }, "family": [ "You lead your household well and provide with strength. Remember your family needs a shepherd more than a CEO (1 Peter 5:2-3: not lording it over them, but being an example).", "Your intensity can flatten tender members of your home. Study your spouse and children like a strategy: what does each need to flourish?", "Do not outsource nurture. Bedtime prayers, long talks, and unhurried presence are executive functions of fatherhood and motherhood.", "Let your family see you repent. A strong leader who apologizes teaches more theology at dinner than most sermons." ], "relationships": [ "You respect strength and candor and are unswervingly loyal to proven friends.", "Your bluntness wounds people who cannot spar at your weight class. Calibrate (Colossians 4:6: speech seasoned with salt, full of grace).", "You debate recreationally; many people experience debate as conflict. Learn each person's rules of engagement.", "Vulnerability feels like exposure to you. Practice it anyway; intimacy runs on it, and even Paul boasted in his weaknesses (2 Corinthians 11:30)." ], "watchouts": [ "Pride and empire-building under a Kingdom letterhead (ask often: whose glory does this serve?)", "Impatience that discards people as \"capacity problems\"", "Anger when crossed or slowed", "Workaholism that starves your soul and your family", "Contempt for weakness, which is where God says His power actually lives (2 Corinthians 12:9)" ], "sanctification": "Surrendered strength. Your question is never capability; it is lordship. The broken-and-commissioned pattern of Paul is your path: ambition crucified, then resurrected as assignment. \"For to me, to live is Christ\" (Philippians 1:21) was written by the most driven man in the New Testament, from a cell, content (Philippians 4:11-13).", "stress": "You accelerate: more control, more hours, more force, less listening. In deep stress you may be ambushed by waves of emotion you have long outrun, or feel suddenly, deeply alone at the top. The remedy is honest peers, real Sabbath, and returning to the feet of the One whose church it actually is (Matthew 16:18: \"I will build my church\").", "disc_natural": "Vision-driven fasting and prayer, disciplined study, bold intercession, sacrificial giving, leadership as worship.", "disc_stretch": "Stillness, submission to others' leadership, unhurried devotion with no output, secret service no one ever discovers.", "verses": [ "\"My grace is sufficient for you, for my power is made perfect in weakness.\" (2 Corinthians 12:9)", "\"Whoever wants to become great among you must be your servant.\" (Matthew 20:26)", "\"Unless the LORD builds the house, the builders labor in vain.\" (Psalm 127:1)" ], "prayer": "Lord of the harvest, You made me to build, and You know how easily I build for myself. Break my ambition the way You broke Saul's, and hand it back as assignment. Make me a servant with a general's gifts. Guard my family from my drive and my soul from my success, and when my strength runs out, teach me to boast in the weakness where Your power lives. Amen.", "next30": [ "Serve once this month in total secrecy, in a role with no authority and no credit.", "Ask your spouse or a close friend, \"Where does my intensity hurt you?\" Listen fully. Do not strategize a response; just repent where needed.", "Take one full Sabbath weekly, and let something at work go visibly undone as an act of trust." ], "temperament": "NT" }, "ENTP": { "code": "ENTP", "name": "The Kingdom Innovator", "mirror": "Solomon in his glory", "also": "Jacob the resourceful; Philip seizing the desert-road moment (Acts 8)", "snapshot": "You are a fountain of ideas with a debater's tongue and an explorer's heart. You see angles no one else sees, question assumptions everyone else salutes, improvise brilliantly, and can argue either side of anything, sometimes just for sport. Life with you is never boring, and neither is church.", "wired": [ "Idea generation at industrial volume", "Quick wit and formidable verbal agility", "Fearless questioning of \"how it's always been done\"", "Improvisation; you are at your best with no script", "Broad curiosity that connects distant fields", "Charm and energy that gather people to new ventures" ], "mirror_story": "Young Solomon, offered anything, asked for a discerning heart (1 Kings 3:9), and what God gave was the ENTP mind at full power: \"God gave Solomon wisdom and very great insight, and a breadth of understanding as measureless as the sand\" (1 Kings 4:29). Look at the range: three thousand proverbs, over a thousand songs, taxonomies of plants, animals, birds, reptiles, and fish (1 Kings 4:32-33), architectural innovation, international trade, and judicial creativity like the sword-and-baby ruling that made a nation hold its breath (1 Kings 3:24-28). Kings and queens traveled continents to test him with hard questions, and he answered them all (1 Kings 10:1-3). Solomon is also your warning label: breadth without guarded devotion drifted him into compromise (1 Kings 11:1-4), and brilliance ended in \"meaningless\" until he circled back to the conclusion of the matter: fear God and keep His commandments (Ecclesiastes 12:13).", "kingdom": "The gospel never changes; its delivery always must. Your calling is innovation and defense: finding the new methods, asking the questions that keep the church honest, debating in the marketplace like Paul in Athens (Acts 17), and connecting the unchanging Word to a changing world.", "church": { "roles": "creative and media ministry, apologetics and open forums, new ministry design, outreach innovation, teaching that engages skeptics, technology adoption, problem-solving task forces, entrepreneurial missions.", "lead": "By ideas and energy. You launch, provoke, reframe, and rally. Pair yourself with finishers and the launches become institutions.", "team_needs": "Fresh options when everyone is stuck, and the courageous questions that expose sacred cows before they crush somebody.", "you_need": "Debate without offense, latitude to experiment, structure support, and leaders secure enough to be questioned." }, "family": [ "Your home gets humor, ideas, and adventure. It also needs your reliability: presence at the same table, promises kept on schedule.", "You win every argument with your spouse and children. Stop it (1 Corinthians 13:5: love keeps no scoreboard). Winning the moment can lose the heart.", "Channel debate into dinner-table discipleship: teach your kids to think, question, and defend their faith. That is your signature gift as a parent.", "Novelty tempts you in every area. Guard covenant with structure: date nights, accountability, and eyes that stay home (Proverbs 5:15-19)." ], "relationships": [ "You are stimulating, funny, and generous with ideas.", "Your devil's-advocate reflex exhausts people who just wanted sympathy. Ask which mode they need before you engage.", "Follow-through builds the trust your charm initiates. Keep small promises relentlessly.", "Depth requires repetition: same people, showing up, again. Resist perpetual novelty in friendship too." ], "watchouts": [ "Arguing for sport until truth becomes a game (2 Timothy 2:14 warns against quarreling about words)", "Chronic starting without finishing", "Boredom with essential routine, in devotion, family, and ministry", "Cleverness drifting into compromise, Solomon's road (1 Kings 11:4)", "Using wit as a weapon or a wall" ], "sanctification": "A guarded heart. Your mind opens a hundred doors, and not all of them should be walked through. \"Above all else, guard your heart, for everything you do flows from it\" (Proverbs 4:23). Ecclesiastes is your cautionary map: every experiment run, every pleasure tested, and the conclusion still waiting where it always was, fear God and keep His commandments (Ecclesiastes 12:13).", "stress": "You spin more plates, crack more jokes, and dodge the real issue with brilliance. In deep stress you may tunnel obsessively into one small worry, or go uncharacteristically flat and withdrawn. The remedy is finishing one concrete thing, honest confession without wit, and worship that engages the body: kneel, sing, lift hands, no commentary.", "disc_natural": "Study across the whole counsel of Scripture, apologetics, creative projects for the Kingdom, discussion groups, brainstorming ministry solutions.", "disc_stretch": "Repetitive liturgy and routine, silence, submission to tradition where it is wise, completing a full read-through plan, praying without arguing a case.", "verses": [ "\"Give your servant a discerning heart.\" (1 Kings 3:9)", "\"Above all else, guard your heart, for everything you do flows from it.\" (Proverbs 4:23)", "\"Fear God and keep his commandments, for this is the duty of all mankind.\" (Ecclesiastes 12:13)" ], "prayer": "God of all wisdom, thank You for a mind that never runs out of doors. Give me Solomon's discernment without Solomon's drift. Guard my heart when my ideas outrun my devotion, make my questions serve Your church rather than my ego, and teach me to finish. Let every clever thing I build stand on the one foundation already laid. Amen.", "next30": [ "Finish, fully and boringly, one project you have already started, before launching anything new.", "In conversations this week, ask three questions for every argument you make.", "Practice one week of \"no devil's advocate\" at home; agree first, explore later." ], "temperament": "NT" } };
export const KDP_TEMPERAMENTS = {"SJ": {"name": "The Pillars", "types": ["ISTJ", "ISFJ", "ESTJ", "ESFJ"], "drive": "Responsibility", "contribution": "Stability and faithfulness", "risk": "Rigidity"}, "SP": {"name": "The Responders", "types": ["ISTP", "ISFP", "ESTP", "ESFP"], "drive": "Action", "contribution": "Hands-on help and joy", "risk": "Impulsiveness"}, "NF": {"name": "The Encouragers", "types": ["INFJ", "INFP", "ENFJ", "ENFP"], "drive": "Meaning", "contribution": "Hearts and relationships", "risk": "Over-idealism"}, "NT": {"name": "The Architects", "types": ["INTJ", "INTP", "ENTJ", "ENTP"], "drive": "Competence", "contribution": "Strategy and truth", "risk": "Intellectual pride"}};
